() => {
  const bodyBg = getComputedStyle(document.body).backgroundColor;
  const bodyColor = getComputedStyle(document.body).color;
  const root = document.documentElement;
  const rootBg = getComputedStyle(root).getPropertyValue('--color-bg').trim();
  const rootText = getComputedStyle(root).getPropertyValue('--color-text').trim();
  const rootMagenta = getComputedStyle(root).getPropertyValue('--color-magenta').trim();
  return { bodyBg, bodyColor, rootBg, rootText, rootMagenta };
}

